def heuristic_fill_rate_alert(fill_rate_data: dict, threshold: float = 0.5, min_placed: int = 3) -> list:
    """Identify strategies with persistent low fill rates (likely limits too tight)."""
    alerts = []
    for strategy, data in fill_rate_data.items():
        placed = data.get("placed", 0)
        rate = data.get("fill_rate", 1.0)
        canceled = data.get("canceled", 0)
        if placed >= min_placed and rate < threshold:
            alerts.append({
                "strategy": strategy,
                "fill_rate": rate,
                "placed": placed,
                "filled": data.get("filled", 0),
                "canceled": canceled,
                "alert": (
                    f"fill rate {rate:.0%} below {threshold:.0%} "
                    f"— {canceled} canceled orders suggest limits too tight"
                ),
            })
    return sorted(alerts, key=lambda x: x["fill_rate"])

