from adapter import heuristic_fill_rate_alert  # noqa: E402


class TestFillRateAlert(unittest.TestCase):
    def test_triggers_on_options_momentum(self):
        data = {"options-momentum": {"placed": 10, "filled": 4, "canceled": 3, "rejected": 0, "fill_rate": 0.4}}
        alerts = heuristic_fill_rate_alert(data)
        self.assertEqual(len(alerts), 1)
        self.assertEqual(alerts[0]["strategy"], "options-momentum")
        self.assertIn("40%", alerts[0]["alert"])

    def test_no_alert_on_high_fill_rate(self):
        data = {"crypto-momentum": {"placed": 5, "filled": 5, "canceled": 0, "rejected": 0, "fill_rate": 1.0}}
        alerts = heuristic_fill_rate_alert(data)
        self.assertEqual(len(alerts), 0)

    def test_no_alert_below_min_placed(self):
        data = {"new-strat": {"placed": 2, "filled": 0, "canceled": 2, "rejected": 0, "fill_rate": 0.0}}
        alerts = heuristic_fill_rate_alert(data)
        self.assertEqual(len(alerts), 0)

    def test_sorted_by_fill_rate_ascending(self):
        data = {
            "strat-b": {"placed": 5, "filled": 2, "canceled": 3, "rejected": 0, "fill_rate": 0.4},
            "strat-a": {"placed": 5, "filled": 1, "canceled": 4, "rejected": 0, "fill_rate": 0.2},
        }
        alerts = heuristic_fill_rate_alert(data)
        self.assertEqual(len(alerts), 2)
        self.assertEqual(alerts[0]["strategy"], "strat-a")
